import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Project, ProjectStatus } from '../../core/models';

interface Tab { label: string; icon: string; path: string; }

/**
 * SiteView project detail shell (`/projects/:id`). Renders the project header +
 * a tab bar that routes to the child feature views (dashboard / schedule /
 * milestones / budget / siteplan) via <router-outlet>. Planner-only "Edit"
 * opens a URL-addressable dialog (`?modal=edit`).
 *
 * DATA CONTRACT: `project` is a signal<Project | null> of mock data; the
 * service_agent stage clears it and wires ApiService.getProject() in ngOnInit.
 */
@Component({
  selector: 'app-project-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive, RouterOutlet],
  templateUrl: './project-detail.component.html',
  styleUrl: './project-detail.component.css',
})
export class ProjectDetailComponent implements OnInit {
  readonly projectId = signal<string>('');
  readonly modal = signal<string | null>(null);

  readonly project = signal<Project | null>({
    id: 'p1',
    name: 'Riverside Community Center',
    status: 'active',
    phaseCount: 3,
    taskCount: 8,
    progressPct: 46,
  });

  readonly tabs: Tab[] = [
    { label: 'Dashboard', icon: '📊', path: 'dashboard' },
    { label: 'Schedule', icon: '📅', path: 'schedule' },
    { label: 'Milestones', icon: '🚩', path: 'milestones' },
    { label: 'Budget', icon: '💰', path: 'budget' },
    { label: 'Site Plan', icon: '🗺️', path: 'siteplan' },
  ];

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
    this.route.queryParamMap.subscribe((q) => this.modal.set(q.get('modal')));
  }

  openEdit(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: 'edit' },
      queryParamsHandling: 'merge',
    });
  }
  closeModal(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }

  statusLabel(s: ProjectStatus): string {
    return { planning: 'Planning', active: 'Active', on_hold: 'On hold', complete: 'Complete' }[s];
  }
  statusClass(s: ProjectStatus): string {
    return { planning: 'badge-muted', active: 'badge-info', on_hold: 'badge-warn', complete: 'badge-ok' }[s];
  }
}
